const RING_MASK: u32 = (RING_SIZE - 1) as u32;

/// Maksimum paket boyutu (jumbo frame desteği)
const MAX_PACKET_SIZE: usize = 9216;

/// Varsayılan MTU
const DEFAULT_MTU: u32 = 1500;

